import type { RunProgress, Scenario } from "./types.js";

const progressStore = new Map<string, RunProgress>();

export function createRunProgress(scenario: Scenario): RunProgress {
  const totalStepsOverall = scenario.testCases.reduce(
    (total, testCase) => total + testCase.steps.length,
    0
  );
  const timestamp = new Date().toISOString();

  return {
    scenarioId: scenario.id,
    scenarioName: scenario.name,
    status: "running",
    startedAt: timestamp,
    updatedAt: timestamp,
    totalTestCases: scenario.testCases.length,
    currentTestCaseIndex: 0,
    totalStepsOverall,
    completedStepsOverall: 0,
    currentStepIndex: 0,
    currentTestCaseTotalSteps: 0,
    message: "실행 준비 중",
  };
}

export function setRunProgress(progress: RunProgress) {
  progressStore.set(progress.scenarioId, progress);
}

export function getRunProgress(scenarioId: string): RunProgress | null {
  return progressStore.get(scenarioId) ?? null;
}

export function updateRunProgress(
  scenarioId: string,
  updater: (current: RunProgress) => RunProgress
): RunProgress | null {
  const current = progressStore.get(scenarioId);

  if (!current) {
    return null;
  }

  const next = updater(current);
  progressStore.set(scenarioId, next);
  return next;
}

export function markSnapshotSaving(scenarioId: string) {
  return updateRunProgress(scenarioId, (current) => ({
    ...current,
    status: "savingSnapshot",
    updatedAt: new Date().toISOString(),
    message: "AS-IS 스냅샷 저장 중",
  }));
}

export function markRunCompleted(scenarioId: string) {
  return updateRunProgress(scenarioId, (current) => ({
    ...current,
    status: "completed",
    updatedAt: new Date().toISOString(),
    currentTestCaseIndex: current.totalTestCases,
    currentStepIndex: current.currentTestCaseTotalSteps,
    completedStepsOverall: current.totalStepsOverall,
    message: "AS-IS 저장 완료",
  }));
}

export function markRunErrored(scenarioId: string, error: string) {
  return updateRunProgress(scenarioId, (current) => ({
    ...current,
    status: "error",
    updatedAt: new Date().toISOString(),
    error,
    message: "실행 중 오류 발생",
  }));
}

