import { chromium, type Browser, type Dialog, type Locator, type Page } from "@playwright/test";
import { normalizeLocator } from "./locator-utils.ts";
import type { Step, StepLocator, StepResult, TiberoConfig } from "./types.js";

interface ExecuteStepsOptions {
  onStepStart?: (step: Step, stepIndex: number) => void | Promise<void>;
  onStepComplete?: (
    result: StepResult,
    stepIndex: number,
    executedStepCount: number
  ) => void | Promise<void>;
}

export class PlaywrightExecutor {
  private browser: Browser | null = null;

  async initialize() {
    this.browser = await chromium.launch({ headless: true });
  }

  async close() {
    await this.browser?.close();
  }

  async executeSteps(
    steps: Step[],
    dbConfig?: TiberoConfig,
    options: ExecuteStepsOptions = {}
  ): Promise<StepResult[]> {
    const page = await this.browser?.newPage();

    if (!page) {
      throw new Error("Browser is not initialized");
    }

    const results: StepResult[] = [];
    const dialogMessages: string[] = [];
    const dialogListener = async (dialog: Dialog) => {
      dialogMessages.push(`${dialog.type()}: ${dialog.message()}`);
      await dialog.accept();
    };

    try {
      page.on("dialog", dialogListener);

      for (const [stepIndex, step] of steps.entries()) {
        await options.onStepStart?.(step, stepIndex);
        const result = await this.executeStep(step, page, dbConfig, dialogMessages);
        results.push(result);
