import { NextResponse } from "next/server";
import type { NextRequest } from "next/server";
import {
  createRunProgress,
  markRunCompleted,
  markRunErrored,
  setRunProgress,
  updateRunProgress,
} from "@/lib/run-progress";
import { getScenario } from "@/lib/scenario-manager";
import { runScenario } from "@/lib/test-runner";

export async function POST(_: NextRequest, { params }: { params: { id: string } }) {
  try {
    const scenario = getScenario(params.id);

    if (!scenario) {
      return NextResponse.json({ success: false, error: "Not found" }, { status: 404 });
    }

    setRunProgress(createRunProgress(scenario));

    const result = await runScenario(scenario, {
      onTestCaseStart: async (testCase, testCaseIndex, totalTestCases) => {
        updateRunProgress(scenario.id, (current) => ({
          ...current,
          status: "running",
          updatedAt: new Date().toISOString(),
          currentTestCaseIndex: testCaseIndex + 1,
          currentTestCaseName: testCase.name,
          currentStepIndex: 0,
          currentStepDescription: undefined,
          currentTestCaseTotalSteps: testCase.steps.length,
          totalTestCases,
          message: `테스트케이스 실행 중: ${testCase.name}`,
        }));
      },
      onStepStart: async (testCase, _testCaseIndex, step, stepIndex) => {
        updateRunProgress(scenario.id, (current) => ({
          ...current,
          updatedAt: new Date().toISOString(),
          currentTestCaseName: testCase.name,
          currentStepIndex: stepIndex + 1,
          currentStepDescription: step.description ?? step.type,
          currentTestCaseTotalSteps: testCase.steps.length,
          message: `Step 실행 중: ${step.description ?? step.type}`,
        }));
      },
      onStepComplete: async () => {
        updateRunProgress(scenario.id, (current) => ({
          ...current,
          updatedAt: new Date().toISOString(),
          completedStepsOverall: Math.min(
            current.completedStepsOverall + 1,
            current.totalStepsOverall
          ),
          message: `전체 ${Math.min(
            current.completedStepsOverall + 1,
            current.totalStepsOverall
          )}개 step 완료`,
        }));
      },
    });

    markRunCompleted(scenario.id);
    return NextResponse.json({ success: true, data: result });
  } catch (error) {
    markRunErrored(params.id, error instanceof Error ? error.message : String(error));
    return NextResponse.json({ success: false, error: String(error) }, { status: 500 });
  }
}

