import fs from "node:fs";
import path from "node:path";
import type { Scenario } from "./types.js";

const SCENARIOS_DIR = path.join(process.cwd(), "data", "scenarios");

function ensureDir() {
  if (!fs.existsSync(SCENARIOS_DIR)) {
    fs.mkdirSync(SCENARIOS_DIR, { recursive: true });
  }
}

function filePath(id: string) {
  return path.join(SCENARIOS_DIR, `${id}.json`);
}

export function listScenarios(): Scenario[] {
  ensureDir();

  return fs
    .readdirSync(SCENARIOS_DIR)
    .filter((entry) => entry.endsWith(".json"))
    .map(
      (entry) => JSON.parse(fs.readFileSync(path.join(SCENARIOS_DIR, entry), "utf-8")) as Scenario
    );
}

export function getScenario(id: string): Scenario | null {
  const target = filePath(id);

  if (!fs.existsSync(target)) {
    return null;
  }

  return JSON.parse(fs.readFileSync(target, "utf-8")) as Scenario;
}

export function saveScenario(scenario: Scenario): void {
  ensureDir();
  fs.writeFileSync(filePath(scenario.id), JSON.stringify(scenario, null, 2), "utf-8");
}

export function deleteScenario(id: string): boolean {
  const target = filePath(id);

  if (!fs.existsSync(target)) {
    return false;
  }

  fs.unlinkSync(target);
  return true;
}

