"use client";

import Link from "next/link";
import { useCallback, useEffect, useState } from "react";
import { CompareView } from "@/components/CompareView";
import { RunProgressView } from "@/components/RunProgressView";
import { RunView } from "@/components/RunView";
import { Button } from "@/components/ui/button";
import type { ComparisonReport, RunProgress, Scenario, ScenarioResult } from "@/lib/types";

type RunMode = "idle" | "running" | "result" | "compare";

export default function RunScenarioPage({ params }: { params: { id: string } }) {
  const [scenario, setScenario] = useState<Scenario | null>(null);
  const [mode, setMode] = useState<RunMode>("idle");
  const [result, setResult] = useState<ScenarioResult | null>(null);
  const [report, setReport] = useState<ComparisonReport | null>(null);
  const [snapshots, setSnapshots] = useState<string[]>([]);
  const [error, setError] = useState<string | null>(null);
  const [progress, setProgress] = useState<RunProgress | null>(null);

  const loadSnapshots = useCallback(async () => {
    const response = await fetch(`/api/scenarios/${params.id}/snapshots`);
    const payload = (await response.json()) as { success: boolean; data?: string[] };

    if (payload.success && payload.data) {
      setSnapshots(payload.data);
    }
  }, [params.id]);

  useEffect(() => {
    void fetch(`/api/scenarios/${params.id}`)
      .then((response) => response.json())
      .then((payload: { success: boolean; data?: Scenario }) => {
        if (payload.success && payload.data) {
          setScenario(payload.data);
        }
      });
    void loadSnapshots();
  }, [loadSnapshots, params.id]);

  useEffect(() => {
    if (mode !== "running") {
      return;
    }

    const intervalId = window.setInterval(() => {
      void fetch(`/api/scenarios/${params.id}/run-status`)
        .then((response) => response.json())
        .then((payload: { success: boolean; data?: RunProgress | null }) => {
          if (payload.success) {
            setProgress(payload.data ?? null);
          }
        })
        .catch(() => {});
    }, 500);

    return () => window.clearInterval(intervalId);
  }, [mode, params.id]);

  async function handleSaveSnapshot() {
    setMode("running");
    setError(null);
    setProgress(null);

    try {
      const runResponse = await fetch(`/api/scenarios/${params.id}/run`, { method: "POST" });
      const runPayload = (await runResponse.json()) as {
        success: boolean;
        data?: ScenarioResult;
        error?: string;
      };

      if (!runPayload.success || !runPayload.data) {
        throw new Error(runPayload.error ?? "실행에 실패했습니다.");
      }

      const snapshotResponse = await fetch(`/api/scenarios/${params.id}/snapshot`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(runPayload.data),
      });
      const snapshotPayload = (await snapshotResponse.json()) as {
        success: boolean;
        error?: string;
      };

      if (!snapshotPayload.success) {
        throw new Error(snapshotPayload.error ?? "스냅샷 저장에 실패했습니다.");
      }

      setResult(runPayload.data);
      setProgress((current) =>
        current
          ? {
              ...current,
              status: "completed",
              message: "AS-IS 저장 완료",
              completedStepsOverall: current.totalStepsOverall,
            }
          : current
      );
      setMode("result");
      await loadSnapshots();
    } catch (caught) {
      setError(String(caught));
      setMode("idle");
    }
  }

  async function handleCompare() {
    setMode("running");
    setError(null);

    try {
      const response = await fetch(`/api/scenarios/${params.id}/compare`, { method: "POST" });
      const payload = (await response.json()) as {
        success: boolean;
        data?: { current: ScenarioResult; report: ComparisonReport };
        error?: string;
      };

      if (!payload.success || !payload.data) {
        throw new Error(payload.error ?? "비교에 실패했습니다.");
      }

      setResult(payload.data.current);
      setReport(payload.data.report);
      setMode("compare");
    } catch (caught) {
      setError(String(caught));
      setMode("idle");
    }
  }

  if (!scenario) {
    return <div className="p-8 text-muted-foreground">로딩 중..</div>;
  }

  return (
    <main className="mx-auto max-w-4xl px-4 py-8">
      <div className="mb-6 flex items-center justify-between">
        <h1 className="text-2xl font-bold">{scenario.name}</h1>
        <Link href="/">
          <Button variant="outline">목록으로</Button>
        </Link>
      </div>

      <div className="mb-4 flex flex-wrap gap-3">
        <Button disabled={mode === "running"} onClick={handleSaveSnapshot}>
          {mode === "running" ? "실행 중.." : "AS-IS로 저장"}
        </Button>
        <Button
          disabled={mode === "running" || snapshots.length === 0}
          onClick={handleCompare}
          variant="outline"
        >
          현재와 비교
        </Button>
      </div>

      {snapshots.length > 0 && (
        <p className="mb-4 text-sm text-muted-foreground">
          저장된 스냅샷 {snapshots.length}개, 최신 파일: {snapshots[0]}
        </p>
      )}

      {error && (
        <div className="mb-4 rounded-lg border border-red-200 bg-red-50 p-3 text-sm text-red-700">
          {error}
        </div>
      )}

      {mode === "running" && <RunProgressView progress={progress} />}

      {mode === "result" && result && <RunView result={result} />}

      {mode === "compare" && report && result && (
        <div className="space-y-6">
          <CompareView report={report} />
          <details className="rounded-lg border p-3">
            <summary className="cursor-pointer text-sm text-muted-foreground">
              현재 실행 결과 상세 보기
            </summary>
            <div className="mt-3">
              <RunView result={result} />
            </div>
          </details>
        </div>
      )}
    </main>
  );
}

