import type { TiberoConfig } from "./types.js";

interface OracleDbMetaData {
  name: string;
}

interface OracleDbExecuteResult {
  rows?: unknown[];
  metaData?: OracleDbMetaData[];
}

interface OracleDbConnection {
  execute(
    query: string,
    binds: unknown[],
    options: {
      outFormat: number | string;
      maxRows: number;
    }
  ): Promise<OracleDbExecuteResult>;
  close(): Promise<void>;
}

interface OracleDbModule {
  OUT_FORMAT_OBJECT: number | string;
  getConnection(options: {
    user: string;
    password: string;
    connectString: string;
  }): Promise<OracleDbConnection>;
}

export interface DbQueryResult {
  rows: unknown[];
  rowCount: number;
  columns: string[];
}

export async function executeDbQuery(config: TiberoConfig, query: string): Promise<DbQueryResult> {
  let oracledbModule: { default?: OracleDbModule };

  try {
    const loadOracleDb = new Function("return import('oracledb')");
    oracledbModule = (await loadOracleDb()) as { default?: OracleDbModule };
  } catch (error) {
    throw new Error(
      "The 'oracledb' package is required for dbQuery steps. Install it before using Tibero queries."
    );
  }

  const oracledb = (oracledbModule.default ?? oracledbModule) as OracleDbModule;
  let connection: OracleDbConnection | undefined;

  try {
    connection = await oracledb.getConnection({
      user: config.username,
      password: config.password,
      connectString: `${config.host}:${config.port}/${config.serviceName}`,
    });

    const result = await connection.execute(query, [], {
      outFormat: oracledb.OUT_FORMAT_OBJECT,
      maxRows: 1000,
    });

    const rows = result.rows ?? [];
    const columns = result.metaData?.map((meta) => meta.name) ?? [];

    return {
      rows,
      rowCount: rows.length,
      columns,
    };
  } finally {
    if (connection !== undefined) {
      await connection.close();
    }
  }
}

