interface StepEditorProps {
  step: Step;
  onChange: (step: Step) => void;
  onRemove: () => void;
}

const STEP_TYPES = [
  "navigate",
  "click",
  "mapClick",
  "fill",
  "select",
  "wait",
  "screenshot",
  "evaluate",
  "dbQuery",
] as const;

const STEP_TYPE_LABELS: Record<(typeof STEP_TYPES)[number], string> = {
  navigate: "페이지 이동",
