  fill: "입력",
  select: "선택",
  wait: "대기",
  screenshot: "스크린샷",
  evaluate: "스크립트 실행",
  dbQuery: "DB 조회",
};

function coerceStep(type: Step["type"]): Step {
  switch (type) {
    case "navigate":
      return { type, url: "", description: "" };
    case "click":
      return { type, locator: {}, description: "" };
    case "mapClick":
      return { type, locator: {}, x: 0, y: 0, description: "" };
    case "fill":
      return { type, locator: {}, text: "", description: "" };
    case "select":
      return { type, locator: {}, text: "", description: "" };
    case "wait":
