import fs from "node:fs";
import path from "node:path";
import type { ScenarioResult } from "./types.js";

const SNAPSHOTS_DIR = path.join(process.cwd(), "data", "snapshots");

function scenarioDir(scenarioId: string) {
  return path.join(SNAPSHOTS_DIR, scenarioId);
}

function ensureDir(scenarioId: string) {
  const target = scenarioDir(scenarioId);

  if (!fs.existsSync(target)) {
    fs.mkdirSync(target, { recursive: true });
  }
}

export function saveSnapshot(result: ScenarioResult): string {
  ensureDir(result.scenarioId);

  const targetDir = scenarioDir(result.scenarioId);
  const filename = `${result.executedAt.replace(/[:.]/g, "-").slice(0, 19)}.json`;
  const serialized = JSON.stringify(result, null, 2);

  fs.writeFileSync(path.join(targetDir, filename), serialized, "utf-8");
  fs.writeFileSync(path.join(targetDir, "latest.json"), serialized, "utf-8");

  return filename;
}

export function loadLatestSnapshot(scenarioId: string): ScenarioResult | null {
  const target = path.join(scenarioDir(scenarioId), "latest.json");

  if (!fs.existsSync(target)) {
    return null;
  }

  return JSON.parse(fs.readFileSync(target, "utf-8")) as ScenarioResult;
}

export function listSnapshots(scenarioId: string): string[] {
  const targetDir = scenarioDir(scenarioId);

  if (!fs.existsSync(targetDir)) {
    return [];
  }

  return fs
    .readdirSync(targetDir)
    .filter((entry) => entry.endsWith(".json") && entry !== "latest.json")
    .sort()
    .reverse();
}

