"use client";

import Link from "next/link";
import { useCallback, useEffect, useState } from "react";
import { CompareView } from "@/components/CompareView";
import { RunProgressView } from "@/components/RunProgressView";
import { RunView } from "@/components/RunView";
import { Button } from "@/components/ui/button";
import type { ComparisonReport, RunProgress, Scenario, ScenarioResult } from "@/lib/types";

type RunMode = "idle" | "running" | "result" | "compare";

export default function RunScenarioPage({ params }: { params: { id: string } }) {
  const [scenario, setScenario] = useState<Scenario | null>(null);
  const [mode, setMode] = useState<RunMode>("idle");
  const [result, setResult] = useState<ScenarioResult | null>(null);
  const [report, setReport] = useState<ComparisonReport | null>(null);
  const [snapshots, setSnapshots] = useState<string[]>([]);
  const [error, setError] = useState<string | null>(null);
  const [progress, setProgress] = useState<RunProgress | null>(null);

  const loadSnapshots = useCallback(async () => {
    const response = await fetch(`/api/scenarios/${params.id}/snapshots`);
    const payload = (await response.json()) as { success: boolean; data?: string[] };

    if (payload.success && payload.data) {
      setSnapshots(payload.data);
    }
  }, [params.id]);

  useEffect(() => {
    void fetch(`/api/scenarios/${params.id}`)
      .then((response) => response.json())
      .then((payload: { success: boolean; data?: Scenario }) => {
        if (payload.success && payload.data) {
          setScenario(payload.data);
        }
      });
    void loadSnapshots();
  }, [loadSnapshots, params.id]);

  useEffect(() => {
    if (mode !== "running") {
      return;
    }

    const intervalId = window.setInterval(() => {
      void fetch(`/api/scenarios/${params.id}/run-status`)
        .then((response) => response.json())
        .then((payload: { success: boolean; data?: RunProgress | null }) => {
          if (payload.success) {
            setProgress(payload.data ?? null);
          }
        })
        .catch(() => {});
    }, 500);

    return () => window.clearInterval(intervalId);
  }, [mode, params.id]);

  async function handleSaveSnapshot() {
    setMode("running");
    setError(null);
    setProgress(null);

    try {
      const runResponse = await fetch(`/api/scenarios/${params.id}/run`, { method: "POST" });
      const runPayload = (await runResponse.json()) as {
        success: boolean;
        data?: ScenarioResult;
        error?: string;
      };

      if (!runPayload.success || !runPayload.data) {
        throw new Error(runPayload.error ?? "실행에 실패했습니다.");
      }

      const snapshotResponse = await fetch(`/api/scenarios/${params.id}/snapshot`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(runPayload.data),
      });
      const snapshotPayload = (await snapshotResponse.json()) as {
        success: boolean;
